+/**
+ * Applies a rule while preserving its scoped ignore regions and every valid
+ * marker line. Markers inside frontmatter, code, or display math are ignored.
+ */
+export function applyScopedRuleIgnore(
+    ruleAlias: string,
+    text: string,
+    knownRuleAliases: Iterable<string>,
+    apply: (text: string) => string,
+): string {
+  const aliases = new Set(Array.from(knownRuleAliases, (alias) => alias.toLowerCase()));
+  const lines = text.split('\
