+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    if (isRuleDisabled(scopes, ruleAlias.toLowerCase())) {
+      protectedLines.add(lineIndex);
+    }
+
+    if (ignoredContext.has(lineIndex)) {
+      continue;
+    }
+
+    const marker = parseMarker(lines[lineIndex], aliases);
+    if (marker === null) {
+      continue;
+    }
+
+    // A syntactically valid marker is immutable even if its arguments do not
+    // produce an active suppression.
+    protectedLines.add(lineIndex);
+
+    if (marker.command === 'disable') {
+      if (!marker.hasRuleList || marker.rules.size > 0) {
+        scopes.push({all: !marker.hasRuleList, rules: marker.rules, enabledRules: new Set<string>()});
+      }
+    } else if (marker.command === 'enable') {
+      enableRules(scopes, marker);
+    } else if (marker.rules.size > 0 || !marker.hasRuleList) {
+      const count = marker.command === 'next-line' ? 1 : marker.lineCount;
+      if (count !== undefined) {
+        for (let offset = 1; offset <= count && lineIndex + offset < lines.length; offset++) {
+          if (!marker.hasRuleList || marker.rules.has(ruleAlias.toLowerCase())) {
+            protectedLines.add(lineIndex + offset);
+          }
+        }
+      }
+    }
+  }
+
+  if (protectedLines.size === 0) {
+    return apply(text);
+  }
+
+  const replacements = new Map<string, string>();
+  const protectedText = lines.map((line, index) => {
+    if (!protectedLines.has(index)) {
+      return line;
+    }
+
+    const placeholder = `\\uE000LINTER_SCOPED_IGNORE_${index}\\uE001`;
+    replacements.set(placeholder, line);
+    return placeholder;
+  }).join('\
